__CPROVER_assigns(__CPROVER_object_whole(freqs), state->m_w, state->m_z)
{
    int i;
    for (i = 0; i < n; i++)
    __CPROVER_assigns(i, __CPROVER_object_whole(freqs), state->m_w, state->m_z)
    __CPROVER_loop_invariant(0 <= i && i <= n)
    {
        if ((Ran(state) >> 4) % 3 == 0)
            freqs[i] = freqs[Ran(state) % n];
