__CPROVER_requires(__CPROVER_is_fresh(state, sizeof(RanState)))
__CPROVER_assigns(state->m_w, state->m_z)
__CPROVER_ensures(state->m_w == 1)
__CPROVER_ensures(state->m_z == 2)
